rss.channel:
Даниил Прокофьев / Daniil Prokofiev
{{ site.BaseURL }}
Статьи на русском и English вместе с постами из потока
Hugo -- gohugo.io
{{ site.Language.Lang }}
{{ with .OutputFormats.Get "RSS" }}
    {{ printf "" .Permalink .MediaType.Type | safeHTML }}
{{ end }}

{{- $feedItems := slice -}}

{{- range site.AllPages -}}
  {{- if and (eq .Kind "page") (not (eq .Type "stream")) -}}

    {{- if not (eq .Params.rss false) -}}
      {{- $item := dict "Title" .Title "Link" .Permalink "Date" .Date "Content" .Content "Lang" .Language.Lang -}}
      {{- $feedItems = $feedItems | append $item -}}
    {{- end -}}

  {{- end -}}
{{- end -}}

{{- $streamPage := site.GetPage "/stream" -}}
{{- if $streamPage -}}
  {{- range $streamPage.Resources.ByType "page" -}}
    {{- $postLang := .Params.language | default "ru" -}}
    {{- $postTitle := printf "Поток [%s] от %s" ($postLang | upper) (.Date.Format "02.01.2006 15:04") -}}
    {{- $postLink := printf "%s#%s" $streamPage.Permalink .File.TranslationBaseName -}}

    {{- $item := dict "Title" $postTitle "Link" $postLink "Date" .Date "Content" .Content "Lang" $postLang -}}
    {{- $feedItems = $feedItems | append $item -}}
  {{- end -}}
{{- end -}}

{{- range sort $feedItems "Date" "desc" -}}


  {{ .Title }}
  {{ .Link }}
  {{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" | safeHTML }}
  {{ .Link }}

    {{- printf "[%s] " (.Lang | upper) | html -}}
    {{- .Content | html -}}


{{- end -}}
